frappe.ui.form.on('Sales Order', {
  refresh(frm) {
    frappe.show_alert({message: 'SO client script loaded ✅', indicator: 'green'});
  }
});

frappe.ui.form.on('Item', {
  refresh(frm) {
    $('.attachment-row .ellipsis').each(function () {
      if (!this.title) this.title = $(this).text();
    });
    frappe.dom.set_style(`
      .attachment-row .ellipsis {
        max-width: none !important;
        white-space: normal !important;
        text-overflow: clip !important;
        word-break: break-all;
      }
    `);
  }
});

frappe.ui.form.on('Item', {
  refresh(frm) {
    // keep it in sync on load
    frm.set_value('custom_item_code_display', frm.doc.item_code || '');
  },
  item_code(frm) {
    // keep it in sync when item_code changes
    frm.set_value('custom_item_code_display', frm.doc.item_code || '');
  }
});

frappe.ui.form.on('BOM Export Package', {
  onload(frm) {
    set_inductone_queries(frm);
  },

  refresh(frm) {
    // Prevent duplicate handlers/buttons on repeated refresh
    frm.clear_custom_buttons();

    // Setup dynamic link filtering
    set_inductone_queries(frm);

    // Don't show buttons on new/unsaved doc
    if (frm.is_new()) return;

    const can_generate = ['Draft', 'Failed', 'Complete'].includes(frm.doc.status);

    if (can_generate) {
      frm.add_custom_button('Generate ZIP', () => inductone_generate_zip(frm));
    }

    if (frm.doc.output_zip) {
      frm.add_custom_button('Download ZIP', () => {
        window.open(frm.doc.output_zip);
      });
    }
  },

  inductone_build(frm) {
    // When build changes, clear dependent selections
    frm.set_value('configuration_order', null);
    frm.set_value('configured_snapshot', null);

    set_inductone_queries(frm);
  }
});


function set_inductone_queries(frm) {

  // Filter Configuration Orders by selected build
  frm.set_query('configuration_order', function() {
    if (!frm.doc.inductone_build) return {};

    return {
      filters: {
        inductone_build: frm.doc.inductone_build
      }
    };
  });

  // Filter Snapshots by selected build
  frm.set_query('configured_snapshot', function() {
    if (!frm.doc.inductone_build) return {};

    return {
      filters: {
        inductone_build: frm.doc.inductone_build
      }
    };
  });
}


async function inductone_generate_zip(frm) {

  if (!frm.doc.bom) {
    frappe.msgprint('Select a BOM first.');
    return;
  }

  if (!(frm.doc.include_pdf || frm.doc.include_stl || frm.doc.include_dxf || frm.doc.include_step)) {
    frappe.msgprint('Select at least one file type (PDF/STL/DXF/STEP).');
    return;
  }

  // Persist any user changes before server reads them
  if (frm.is_dirty()) {
    await frm.save();
  }

  frappe.dom.freeze('Generating export…');

  try {

    await frappe.call({
      method: "inductone_tools.bom_export.generate_now",
      args: { package_name: frm.doc.name }
    });

    // Hard reload avoids optimistic lock conflicts
    window.location.reload();

  } catch (e) {

    console.error(e);

    frappe.msgprint({
      title: 'Generate ZIP Failed',
      message: e?.message || e,
      indicator: 'red'
    });

  } finally {
    frappe.dom.unfreeze();
  }
}

frappe.ui.form.on('InductOne Configuration Option Mapping', {
  // Runs when a mapping row is edited in the grid
  qty_source(frm, cdt, cdn) {
    const row = locals[cdt][cdn];

    // Phase 1 guard: do not allow FROM_SELECTION yet
    if (row.qty_source === "FROM_SELECTION") {
      row.qty_source = "FIXED";
      row.parameter_key = "";
      frappe.msgprint({
        title: "Not Yet Implemented",
        indicator: "orange",
        message: "FROM_SELECTION is disabled until InductOne Build Option Selection is implemented. Use FIXED for now."
      });
      frm.refresh_field("mappings_table");
    }
  },

  refresh(frm) {
    // Also enforce during refresh in case old rows exist
    (frm.doc.mappings_table || []).forEach(r => {
      if (r.qty_source === "FROM_SELECTION") {
        r.qty_source = "FIXED";
        r.parameter_key = "";
      }
    });
  }
});


