frappe.ui.form.on('Sales Order', {
  refresh(frm) {
    frm.add_custom_button('Create InductOne Build (selected line)', async () => {
      // 1) Resolve selected SO Item row
      const selected = (frm.get_selected && frm.get_selected().items || [])[0];
      if (!selected) {
        return frappe.msgprint('Select a Sales Order Item row first.');
      }
      const line = (frm.doc.items || []).find(it => it.name === selected);
      if (!line) {
        return frappe.throw('Could not resolve selected Sales Order Item row.');
      }

      // 2) Determine top item and orientation
      const top_item = line.item_code;
      const orientation =
        (line.custom_inductone_orientation || frm.doc.custom_inductone_orientation || 'RH_ONLY').trim();

      // 3) Create InductOne Build doc
      const build_doc = {
        doctype: 'InductOne Build',
        sales_order: frm.doc.name,
        sales_order_item_idx: line.idx,
        sales_order_item_row_name: line.name,
        customer_project_label: frm.doc.customer_name || frm.doc.customer || '',
        top_item: top_item,
        orientation: orientation,
        build_status: 'DRAFT'
      };

      const r = await frappe.call({
        method: 'frappe.client.insert',
        args: { doc: build_doc },
        freeze: true,
        freeze_message: 'Creating InductOne Build…'
      });

      const name = r.message && r.message.name;
      if (!name) {
        return frappe.throw('Failed to create InductOne Build.');
      }

      frappe.set_route('Form', 'InductOne Build', name);
    }, 'InductOne');
  }
});

async function fetch_active_options() {
  // Pull active + usable options from catalog
  const r = await frappe.call({
    method: 'frappe.client.get_list',
    args: {
      doctype: 'InductOne Configuration Option',
      fields: ['name', 'option_code', 'option_name', 'option_category', 'option_group', 'sort_order', 'is_active', 'status'],
      filters: {
        is_active: 1,
        status: ['in', ['Defined-Ops', 'Released']]
      },
      order_by: 'sort_order asc'
    }
  });
  return r.message || [];
}

function ensure_group_exclusivity(frm, row) {
  const group = (row.option_group || '').trim();
  if (!group) return;

  // If a row is selected, unselect any other selected option in same group
  if (row.selected) {
    (frm.doc.selections || []).forEach(r => {
      if (r.name === row.name) return;
      if ((r.option_group || '').trim() === group && r.selected) {
        r.selected = 0;
      }
    });
    frm.refresh_field('selections');
  }
}

frappe.ui.form.on('InductOne Build', {
  onload(frm) {
    if (frm.doc.build_status === 'RELEASED_TO_BUILDER') {
      frm.set_df_property('builder_supplier', 'read_only', 1);
      frm.set_df_property('top_item', 'read_only', 1);
      frm.set_df_property('top_bom', 'read_only', 1);
      frm.set_df_property('orientation', 'read_only', 1);
      frm.set_df_property('selections', 'read_only', 1);

      // Lock winner snapshot selection after release
      frm.set_df_property('selected_snapshot', 'read_only', 1);
    }

    // Constrain selected_snapshot to this build's snapshots
    if (frm.fields_dict && frm.fields_dict.selected_snapshot) {
      frm.set_query('selected_snapshot', function() {
        return {
          filters: {
            inductone_build: frm.doc.name
          }
        };
      });
    }

    // Optional: constrain latest_bom_export_package to packages for this build
    if (frm.fields_dict && frm.fields_dict.latest_bom_export_package) {
      frm.set_query('latest_bom_export_package', function() {
        return {
          filters: {
            inductone_build: frm.doc.name
          }
        };
      });
    }
  },

  refresh(frm) {
    // Button: Load catalog options into the selection table
    frm.add_custom_button('Load Catalog Options', async () => {
      await window.por_run_with_logging(frm, 'LOAD_CATALOG', async () => {
        const opts = await fetch_active_options();
        if (!opts.length) {
          frappe.msgprint('No active Released/Defined-Ops options found.');
          return { loaded: 0 };
        }

        // Build a map of existing option links to avoid duplicates
        const existing = new Set((frm.doc.selections || []).map(r => r.option));

        let added = 0;
        for (const o of opts) {
          if (existing.has(o.name)) continue;

          // Populate metadata fields if they exist on the selection child doctype
          frm.add_child('selections', {
            option: o.name,
            option_code: o.option_code,
            option_name: o.option_name,
            option_category: o.option_category,
            option_group: o.option_group,

            selected: 0,
            qty: 1,
            parameter_value: '',
            notes: ''
          });

          added += 1;
        }

        frm.refresh_field('selections');
        frappe.show_alert({ message: `Loaded ${added} options into selections.`, indicator: 'green' });
        return { loaded: added, total_catalog: opts.length };
      });
    }, 'InductOne');

    // Generate snapshot
    frm.add_custom_button('Generate Snapshot', async () => {
      await window.por_run_with_logging(frm, 'GENERATE_SNAPSHOT', async () => {
        return await window.por_generate_snapshot_from_build(frm);
      });
    }, 'InductOne');

    // Generate configuration order
    frm.add_custom_button('Generate Configuration Order', async () => {
      await window.por_run_with_logging(frm, 'GENERATE_CONFIG_ORDER', async () => {
        return await window.por_generate_configuration_order(frm);
      });
    }, 'InductOne');

    // Winner snapshot helpers
    if (frm.fields_dict && frm.fields_dict.selected_snapshot) {
      frm.add_custom_button('Set Selected Snapshot = Latest Snapshot', async () => {
        await window.por_run_with_logging(frm, 'SET_SELECTED_SNAPSHOT', async () => {
          if (!frm.doc.latest_snapshot) {
            throw new Error('No Latest Snapshot to select. Generate a snapshot first.');
          }

          await frappe.call({
            method: 'frappe.client.set_value',
            args: {
              doctype: 'InductOne Build',
              name: frm.doc.name,
              fieldname: { selected_snapshot: frm.doc.latest_snapshot }
            }
          });

          await frm.reload_doc();
          frappe.show_alert({ message: `Selected Snapshot set to ${frm.doc.selected_snapshot}`, indicator: 'green' });
          return { selected_snapshot: frm.doc.selected_snapshot };
        });
      }, 'InductOne');

      frm.add_custom_button('Open Selected Snapshot', async () => {
        await window.por_run_with_logging(frm, 'OPEN_SELECTED_SNAPSHOT', async () => {
          if (!frm.doc.selected_snapshot) {
            throw new Error('No Selected Snapshot set.');
          }
          frappe.set_route('Form', 'Configured BOM Snapshot', frm.doc.selected_snapshot);
          return { opened: frm.doc.selected_snapshot };
        });
      }, 'InductOne');
    }

    // BOM Export Package pipeline entrypoint
    frm.add_custom_button('Open BOM Export Package', async () => {
      await window.por_run_with_logging(frm, 'OPEN_BOM_EXPORT_PACKAGE', async () => {
        return await window.por_open_or_create_bom_export_package(frm);
      });
    }, 'InductOne');

    // Release to builder
    frm.add_custom_button('Release To Builder', async () => {
      await window.por_run_with_logging(frm, 'RELEASE_TO_BUILDER', async () => {
        return await window.por_release_build(frm);
      });
    }, 'InductOne');

    // Debug helper buttons
    frm.add_custom_button('Copy Debug Bundle', async () => {
      const txt = frm.doc.last_debug_bundle || '';
      await navigator.clipboard.writeText(txt);
      frappe.msgprint('Debug bundle copied to clipboard.');
    }, 'InductOne');

    frm.add_custom_button('Download Debug Bundle', () => {
      const txt = frm.doc.last_debug_bundle || '{}';
      const blob = new Blob([txt], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${frm.doc.name || 'build'}-debug.json`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      URL.revokeObjectURL(url);
    }, 'InductOne');
  }
});

frappe.ui.form.on('InductOne Build Option Selection', {
  selected(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    ensure_group_exclusivity(frm, row);
  }
});

// ---------- Helpers: BOM Export Package ----------
window.por_open_or_create_bom_export_package = async function(frm) {
  if (!frm.doc.top_bom) {
    throw new Error('Top BOM is required before creating a BOM Export Package.');
  }

  const configured_snapshot = frm.doc.selected_snapshot || frm.doc.latest_snapshot;
  if (!configured_snapshot) {
    throw new Error('Generate a snapshot first.');
  }

  const configuration_order = frm.doc.latest_config_order;
  if (!configuration_order) {
    throw new Error('Generate a configuration order first.');
  }

  const inductone_build = frm.doc.name;

  // If build already points to a package, open it directly
  const direct =
    frm.doc.latest_bom_export_package ||
    frm.doc.bom_export_package ||
    frm.doc.export_package;

  if (direct) {
    frappe.set_route('Form', 'BOM Export Package', direct);
    return { routed: 'form', name: direct, source: 'direct_pointer' };
  }

  // Otherwise look for an existing matching package for this exact build/config/snapshot
  const existing = await frappe.call({
    method: 'frappe.client.get_list',
    args: {
      doctype: 'BOM Export Package',
      fields: ['name'],
      filters: {
        inductone_build: inductone_build,
        configuration_order: configuration_order,
        configured_snapshot: configured_snapshot
      },
      order_by: 'modified desc',
      limit: 1
    }
  });

  const existing_name = existing.message && existing.message[0] && existing.message[0].name;
  if (existing_name) {
    await window.por_set_latest_bom_export_package_if_field_exists(frm, existing_name);
    frappe.set_route('Form', 'BOM Export Package', existing_name);
    return { routed: 'form', name: existing_name, source: 'existing_match' };
  }

  // Create a configured package doc pre-populated from this build
  const package_doc = {
    doctype: 'BOM Export Package',
    source_mode: 'Configured Build',
    bom: frm.doc.top_bom,
    inductone_build: inductone_build,
    configuration_order: configuration_order,
    configured_snapshot: configured_snapshot,

    include_pdf: 1,
    include_stl: 0,
    include_step: 0,
    include_dxf: 0,
    include_item_attachments: 1,
    include_bom_attachments: 1,
    explosion_mode: 'Follow Explicit Child BOM Links',
    include_qty: 1
  };

  const inserted = await frappe.call({
    method: 'frappe.client.insert',
    args: { doc: package_doc },
    freeze: true,
    freeze_message: 'Creating BOM Export Package…'
  });

  const pkg = inserted.message && inserted.message.name;
  if (!pkg) {
    throw new Error('Failed to create BOM Export Package.');
  }

  await window.por_set_latest_bom_export_package_if_field_exists(frm, pkg);
  await frm.reload_doc();

  frappe.set_route('Form', 'BOM Export Package', pkg);
  return { routed: 'form', name: pkg, source: 'created_new' };
};

window.por_set_latest_bom_export_package_if_field_exists = async function(frm, package_name) {
  if (!(frm.fields_dict && frm.fields_dict.latest_bom_export_package)) {
    return;
  }

  await frappe.call({
    method: 'frappe.client.set_value',
    args: {
      doctype: 'InductOne Build',
      name: frm.doc.name,
      fieldname: {
        latest_bom_export_package: package_name
      }
    }
  });
};

// ---------- Helpers: BOM resolution ----------
async function por_get_default_bom(item_code) {
  // 1) Try default active BOM
  let r = await frappe.call({
    method: 'frappe.client.get_value',
    args: {
      doctype: 'BOM',
      fieldname: 'name',
      filters: { item: item_code, is_active: 1, is_default: 1 }
    }
  });
  let name = r.message && r.message.name;
  if (name) return name;

  // 2) Fallback: any active BOM
  r = await frappe.call({
    method: 'frappe.client.get_list',
    args: {
      doctype: 'BOM',
      fields: ['name'],
      filters: { item: item_code, is_active: 1 },
      limit: 1
    }
  });
  return (r.message && r.message[0] && r.message[0].name) || null;
}

async function por_get_bom(name) {
  const r = await frappe.call({
    method: 'frappe.client.get',
    args: { doctype: 'BOM', name }
  });
  return r.message;
}

// Explode BOM to leaf item lines (flat)
async function por_explode_bom_to_leaf_lines(bom_name, factor, out_lines) {
  const bom = await por_get_bom(bom_name);
  const base_qty = parseFloat(bom.quantity || 1);

  for (const bi of (bom.items || [])) {
    const child_qty = parseFloat(bi.qty || 0);
    const line_factor = factor * (child_qty / base_qty);

    if (bi.bom_no) {
      await por_explode_bom_to_leaf_lines(bi.bom_no, line_factor, out_lines);
    } else {
      out_lines.push({
        item_code: bi.item_code,
        item_name: bi.item_name,
        description: bi.description,
        uom: bi.uom,
        qty: line_factor
      });
    }
  }
}

// Roll-up leaf lines into a qty map by item_code
function por_rollup_qty_map(lines) {
  const m = {};
  for (const ln of lines) {
    const key = ln.item_code;
    if (!m[key]) {
      m[key] = {
        item_code: ln.item_code,
        item_name: ln.item_name,
        description: ln.description,
        uom: ln.uom,
        qty: 0
      };
    }
    m[key].qty += (parseFloat(ln.qty) || 0);
  }
  return m;
}

// ---------- Helpers: Option Actions ----------
async function por_fetch_option_actions(option_name) {
  const r = await frappe.call({
    method: 'frappe.client.get',
    args: { doctype: 'InductOne Configuration Option', name: option_name }
  });
  const doc = r.message;
  return (doc && doc.mappings_table) || [];
}

async function por_expand_target_set(mapping_row) {
  const target_item = mapping_row.target_item;
  const expand_mode = (mapping_row.expand_mode || 'AS_ITEM_ONLY').trim();

  if (!target_item) {
    throw new Error('Mapping row missing target_item.');
  }

  if (expand_mode === 'AS_ITEM_ONLY') {
    return { items: [target_item], resolved_from: 'AS_ITEM_ONLY', rollup_map: null };
  }

  if (expand_mode === 'EXPLODE_DEFAULT_BOM') {
    const bom = await por_get_default_bom(target_item);
    if (!bom) {
      throw new Error(`No active BOM found for target item ${target_item} (expand default BOM).`);
    }
    const lines = [];
    await por_explode_bom_to_leaf_lines(bom, 1.0, lines);
    const rollup = por_rollup_qty_map(lines);
    const set = Object.keys(rollup);
    return { items: set, resolved_from: bom, rollup_map: rollup };
  }

  if (expand_mode === 'USE_TARGET_BOM') {
    const bom = mapping_row.target_bom;
    if (!bom) {
      throw new Error(`Expand mode USE_TARGET_BOM requires target_bom for item ${target_item}.`);
    }
    const lines = [];
    await por_explode_bom_to_leaf_lines(bom, 1.0, lines);
    const rollup = por_rollup_qty_map(lines);
    const set = Object.keys(rollup);
    return { items: set, resolved_from: bom, rollup_map: rollup };
  }

  throw new Error(`Unknown expand_mode: ${expand_mode}`);
}

function por_get_mapping_qty(mapping_row, selection_row) {
  const src = (mapping_row.qty_source || 'FIXED').trim();
  if (src === 'FIXED') {
    return parseFloat(mapping_row.qty_fixed || 0);
  }
  if (src === 'FROM_SELECTION') {
    return parseFloat(selection_row.qty || 0);
  }
  return 0;
}

// Apply mappings to a qty map in deterministic order
async function por_apply_option_actions(final_map, selected_rows) {
  const audit = []; // for configuration order delta lines

  for (const sel of selected_rows) {
    const option_name = sel.option;
    const option_code = sel.option_code;

    const mappings = await por_fetch_option_actions(option_name);

    for (const mr of mappings) {
      if (mr.required_for_release === 0) {
        // governance only for now
      }

      const action = (mr.action || 'ADD').trim();
      const qty = por_get_mapping_qty(mr, sel);

      const expanded = await por_expand_target_set(mr);
      const targets = expanded.items;

      for (const item_code of targets) {
        if (action === 'REMOVE') {
          if (expanded.rollup_map) {
            const per = expanded.rollup_map[item_code] ? (parseFloat(expanded.rollup_map[item_code].qty) || 0) : 0;
            const dec = qty * per;

            if (final_map[item_code]) {
              final_map[item_code].qty -= dec;
              if ((parseFloat(final_map[item_code].qty) || 0) <= 0) {
                delete final_map[item_code];
              }
            }

            audit.push({
              delta_type: 'QTY_OVERRIDE',
              item_code,
              qty: dec,
              source_option_code: option_code,
              reason: `REMOVE (decrement) via ${mr.expand_mode} (${expanded.resolved_from})`
            });
          } else {
            if (final_map[item_code]) {
              delete final_map[item_code];
            }
            audit.push({
              delta_type: 'REMOVE',
              item_code,
              qty: 0,
              source_option_code: option_code,
              reason: `REMOVE via ${mr.expand_mode} (${expanded.resolved_from})`
            });
          }
          continue;
        }

        if (action === 'ADD') {
          if (!final_map[item_code]) {
            final_map[item_code] = { item_code, qty: 0 };
          }
          final_map[item_code].qty += qty;
          audit.push({
            delta_type: 'ADD',
            item_code,
            qty,
            source_option_code: option_code,
            reason: `ADD via ${mr.expand_mode} (${expanded.resolved_from})`
          });
          continue;
        }

        if (action === 'QTY_OVERRIDE') {
          if (!final_map[item_code]) {
            final_map[item_code] = { item_code, qty: 0 };
          }
          final_map[item_code].qty = qty;
          audit.push({
            delta_type: 'QTY_OVERRIDE',
            item_code,
            qty,
            source_option_code: option_code,
            reason: `QTY_OVERRIDE via ${mr.expand_mode} (${expanded.resolved_from})`
          });
          continue;
        }

        if (action === 'REPLACE') {
          if (final_map[item_code]) delete final_map[item_code];
          if (!final_map[item_code]) final_map[item_code] = { item_code, qty: 0 };
          final_map[item_code].qty += qty;
          audit.push({
            delta_type: 'REPLACE',
            item_code,
            qty,
            source_option_code: option_code,
            reason: `REPLACE (REMOVE+ADD) via ${mr.expand_mode} (${expanded.resolved_from})`
          });
          continue;
        }

        throw new Error(`Unknown action: ${action}`);
      }
    }
  }

  return audit;
}

// ---------- MAIN: Generate Snapshot ----------
window.por_generate_snapshot_from_build = async function(frm) {
  if (!frm.doc.sales_order) throw new Error('Sales Order is required.');
  if (!frm.doc.top_item) throw new Error('Top Item is required.');
  if (!frm.doc.builder_supplier) throw new Error('Builder (Supplier) is required.');

  frappe.show_alert({ message: 'Generating snapshot…', indicator: 'blue' });

  const top_item = frm.doc.top_item;
  let top_bom = frm.doc.top_bom;
  if (!top_bom) {
    top_bom = await por_get_default_bom(top_item);
    if (!top_bom) throw new Error(`No active default BOM found for top item ${top_item}.`);
  }

  const base_lines = [];
  await por_explode_bom_to_leaf_lines(top_bom, 1.0, base_lines);
  const baseline_map = por_rollup_qty_map(base_lines);

  const final_map = {};
  for (const k of Object.keys(baseline_map)) {
    final_map[k] = { ...baseline_map[k] };
  }

  const selected = (frm.doc.selections || []).filter(r => r.selected);
  const audit = await por_apply_option_actions(final_map, selected);

  const snapshot_lines = [];

  for (const ic of Object.keys(final_map)) {
    const ln = final_map[ic];
    snapshot_lines.push({
      item_code: ic,
      item_name: ln.item_name || '',
      description: ln.description || '',
      uom: ln.uom || '',
      qty: ln.qty,
      included: 1,
      rule_reason: 'Included by configuration'
    });
  }

  for (const ic of Object.keys(baseline_map)) {
    if (final_map[ic]) continue;
    const ln = baseline_map[ic];
    snapshot_lines.push({
      item_code: ic,
      item_name: ln.item_name || '',
      description: ln.description || '',
      uom: ln.uom || '',
      qty: ln.qty,
      included: 0,
      rule_reason: 'Removed by option actions'
    });
  }

  const next_rev = (parseInt(frm.doc.snapshot_rev || 0, 10) || 0) + 1;

  const snapshot_doc = {
    doctype: 'Configured BOM Snapshot',
    sales_order: frm.doc.sales_order,
    inductone_build: frm.doc.name,
    top_item: top_item,
    top_bom: top_bom,
    orientation: frm.doc.orientation,
    options_csv: '',
    snapshot_rev: next_rev,
    generated_at: frappe.datetime.now_datetime(),
    lines: snapshot_lines,
    delta_lines: (audit || []).map(a => ({
      delta_type: a.delta_type,
      item: a.item_code,
      qty: a.qty || 0,
      source_option_code: a.source_option_code || '',
      reason: a.reason || ''
    }))
  };

  const inserted = await frappe.call({
    method: 'frappe.client.insert',
    args: { doc: snapshot_doc },
    freeze: true,
    freeze_message: 'Saving Snapshot…'
  });

  const snapname = inserted.message && inserted.message.name;
  if (!snapname) throw new Error('Snapshot insert failed.');

  await frappe.call({
    method: 'frappe.client.set_value',
    args: {
      doctype: 'InductOne Build',
      name: frm.doc.name,
      fieldname: {
        top_bom: top_bom,
        snapshot_rev: next_rev,
        latest_snapshot: snapname
      }
    }
  });

  await frm.reload_doc();

  frappe.msgprint(`Snapshot <b>${snapname}</b> created.`);
  return { snapshot_name: snapname, audit };
};

window.por_generate_configuration_order = async function(frm) {
  if (!frm.doc.sales_order) throw new Error('Sales Order is required.');
  if (!frm.doc.top_item) throw new Error('Top Item is required.');
  if (!frm.doc.builder_supplier) throw new Error('Builder (Supplier) is required.');

  let snap = frm.doc.selected_snapshot || frm.doc.latest_snapshot;
  let audit = [];

  if (!snap) {
    const r = await window.por_generate_snapshot_from_build(frm);
    snap = r.snapshot_name;
    audit = r.audit || [];
  }

  const snapDocResp = await frappe.call({
    method: 'frappe.client.get',
    args: { doctype: 'Configured BOM Snapshot', name: snap }
  });
  const snapDoc = snapDocResp && snapDocResp.message;

  if (snapDoc && snapDoc.inductone_build && frm.doc.name && snapDoc.inductone_build !== frm.doc.name) {
    throw new Error(`Selected snapshot ${snap} belongs to build ${snapDoc.inductone_build}, not ${frm.doc.name}.`);
  }

  const next_rev = (parseInt(frm.doc.config_order_rev || 0, 10) || 0) + 1;

  const latestBomExportPackage =
    frm.doc.latest_bom_export_package ||
    frm.doc.bom_export_package ||
    frm.doc.export_package ||
    '';

  // If we already have a package, try to fetch it so we can seed document metadata
  let bomExportPackageDoc = null;
  if (latestBomExportPackage) {
    const pkgResp = await frappe.call({
      method: 'frappe.client.get',
      args: {
        doctype: 'BOM Export Package',
        name: latestBomExportPackage
      }
    });
    bomExportPackageDoc = pkgResp && pkgResp.message;
  }

  const order_doc = {
    doctype: 'InductOne Configuration Order',
    inductone_build: frm.doc.name,
    config_order_rev: next_rev,
    generated_at: frappe.datetime.now_datetime(),
    generated_by: frappe.session.user,

    builder_supplier: frm.doc.builder_supplier,
    sales_order: frm.doc.sales_order,
    sales_order_item_idx: frm.doc.sales_order_item_idx,
    customer_project_label: frm.doc.customer_project_label || '',

    top_item: frm.doc.top_item,
    top_bom: frm.doc.top_bom,
    orientation: frm.doc.orientation,
    snapshot: snap,

    bom_export_package: latestBomExportPackage || '',
    selected_options: [],
    delta_lines: [],
    documents: []
  };

  const selected = (frm.doc.selections || []).filter(r => r.selected);
  for (const s of selected) {
    order_doc.selected_options.push({
      option: s.option,
      option_code: s.option_code,
      option_name: s.option_name,
      qty: s.qty || 1,
      parameter_value: s.parameter_value || '',
      notes: s.notes || ''
    });
  }

  for (const dl of ((snapDoc && snapDoc.delta_lines) || [])) {
    order_doc.delta_lines.push({
      delta_type: dl.delta_type,
      item: dl.item,
      qty: dl.qty || 0,
      source_option_code: dl.source_option_code || '',
      reason: dl.reason || ''
    });
  }

  // Seed document index row for BOM Export Package if one already exists
  if (latestBomExportPackage) {
    order_doc.documents.push({
      source_type: 'BOM',
      source_name: frm.doc.top_bom || '',
      doc_type: 'OTHER',
      doc_title: `Configured BOM Export Package - ${latestBomExportPackage}`,
      file_url: (bomExportPackageDoc && bomExportPackageDoc.output_zip) || '',
      required: 'YES',
      sort_order: 300,
      small_text_vtsj: `BOM Export Package: ${latestBomExportPackage} | Status: ${(bomExportPackageDoc && bomExportPackageDoc.status) || 'Draft'}`
    });
  }

  const inserted = await frappe.call({
    method: 'frappe.client.insert',
    args: { doc: order_doc },
    freeze: true,
    freeze_message: 'Saving Configuration Order…'
  });

  const order_name = inserted.message && inserted.message.name;
  if (!order_name) throw new Error('Configuration order insert failed.');

  await frappe.call({
    method: 'frappe.client.set_value',
    args: {
      doctype: 'InductOne Build',
      name: frm.doc.name,
      fieldname: {
        config_order_rev: next_rev,
        latest_config_order: order_name
      }
    }
  });

  // If a package already existed, update it to point back to the newly-created config order
  if (latestBomExportPackage) {
    await frappe.call({
      method: 'frappe.client.set_value',
      args: {
        doctype: 'BOM Export Package',
        name: latestBomExportPackage,
        fieldname: {
          configuration_order: order_name
        }
      }
    });
  }

  await frm.reload_doc();

  frappe.msgprint(`Configuration Order <b>${order_name}</b> created.`);
  frappe.set_route('Form', 'InductOne Configuration Order', order_name);
  return {
    config_order: order_name,
    snapshot: snap,
    selected_options: order_doc.selected_options.length,
    bom_export_package: latestBomExportPackage || ''
  };
};

window.por_release_build = async function(frm) {
  if (!frm.doc.builder_supplier) throw new Error('Builder (Supplier) is required.');

  const snap = frm.doc.selected_snapshot || frm.doc.latest_snapshot;
  if (!snap) throw new Error('Generate a snapshot (and optionally select a winner) before release.');

  if (!frm.doc.latest_config_order) throw new Error('Generate a configuration order before release.');

  const cfg = await frappe.call({
    method: 'frappe.client.get',
    args: { doctype: 'InductOne Configuration Order', name: frm.doc.latest_config_order }
  });
  const cfgDoc = cfg && cfg.message;
  if (cfgDoc && cfgDoc.snapshot && cfgDoc.snapshot !== snap) {
    throw new Error(
      `Latest Configuration Order (${frm.doc.latest_config_order}) was generated from snapshot ${cfgDoc.snapshot}, ` +
      `but the build is currently pointing to snapshot ${snap}. Re-generate the configuration order from the winner snapshot before release.`
    );
  }

  await frappe.call({
    method: 'frappe.client.set_value',
    args: {
      doctype: 'InductOne Build',
      name: frm.doc.name,
      fieldname: {
        build_status: 'RELEASED_TO_BUILDER',
        released_at: frappe.datetime.now_datetime(),
        released_by: frappe.session.user
      }
    }
  });

  await frm.reload_doc();
  frappe.show_alert({ message: 'Build released to builder.', indicator: 'green' });
};

window.por_run_with_logging = async function(frm, action, fn) {
  const started_at = frappe.datetime.now_datetime();

  frm.set_value('last_action', action);
  frm.set_value('last_result', 'RUNNING');
  frm.set_value('last_run_at', started_at);
  frm.set_value('last_error_summary', '');
  frm.set_value('last_error_detail', '');

  const base_bundle = window.por_build_debug_bundle(frm, action);

  window.por_append_execution_log(frm, {
    timestamp: started_at,
    action,
    result: 'RUNNING',
    summary: 'Started',
    detail: '',
    debug_bundle: JSON.stringify(base_bundle, null, 2)
  });

  try {
    const result = await fn();

    frm.set_value('last_result', 'SUCCESS');
    frm.set_value('last_run_at', frappe.datetime.now_datetime());

    const bundle = window.por_build_debug_bundle(frm, action, { result });
    frm.set_value('last_debug_bundle', JSON.stringify(bundle, null, 2));

    window.por_append_execution_log(frm, {
      timestamp: frappe.datetime.now_datetime(),
      action,
      result: 'SUCCESS',
      summary: 'Completed',
      detail: '',
      debug_bundle: JSON.stringify(bundle, null, 2)
    });

    await frm.save();

    frappe.show_alert({ message: `${action}: Success`, indicator: 'green' });
    return result;

  } catch (e) {
    console.error(e);

    const summary = (e && e.message) ? e.message : String(e);
    const detail = (e && e.stack) ? e.stack : JSON.stringify(e, null, 2);

    frm.set_value('last_result', 'ERROR');
    frm.set_value('last_run_at', frappe.datetime.now_datetime());
    frm.set_value('last_error_summary', summary);
    frm.set_value('last_error_detail', detail);

    const bundle = window.por_build_debug_bundle(frm, action, { error: summary, stack: detail });
    frm.set_value('last_debug_bundle', JSON.stringify(bundle, null, 2));

    window.por_append_execution_log(frm, {
      timestamp: frappe.datetime.now_datetime(),
      action,
      result: 'ERROR',
      summary,
      detail,
      debug_bundle: JSON.stringify(bundle, null, 2)
    });

    await frm.save();

    frappe.msgprint({
      title: `${action} Failed`,
      message: `<pre style="white-space:pre-wrap">${frappe.utils.escape_html(summary)}</pre>`,
      indicator: 'red'
    });

    throw e;
  }
};

window.por_append_execution_log = function(frm, row) {
  if (!frm.doc.execution_log) return;

  const MAX_LOG_ROWS = 50;
  if ((frm.doc.execution_log || []).length >= MAX_LOG_ROWS) {
    frm.doc.execution_log = (frm.doc.execution_log || []).slice(-1 * (MAX_LOG_ROWS - 1));
    frm.refresh_field('execution_log');
  }

  const child = frm.add_child('execution_log');
  child.timestamp = row.timestamp || frappe.datetime.now_datetime();
  child.action = row.action || '';
  child.result = row.result || '';
  child.summary = row.summary || '';
  child.detail = row.detail || '';
  child.debug_bundle = '';
};

window.por_build_debug_bundle = function(frm, action, extra) {
  const selected = (frm.doc.selections || []).filter(r => r.selected).map(r => ({
    option: r.option,
    option_code: r.option_code,
    option_name: r.option_name,
    qty: r.qty || 1,
    parameter_value: r.parameter_value || '',
    notes: r.notes || ''
  }));

  return {
    version: 'debug_bundle_v1',
    action,
    when: frappe.datetime.now_datetime(),
    user: frappe.session && frappe.session.user,
    doctype: frm.doc.doctype,
    docname: frm.doc.name,
    key_fields: {
      sales_order: frm.doc.sales_order,
      builder_supplier: frm.doc.builder_supplier,
      top_item: frm.doc.top_item,
      top_bom: frm.doc.top_bom,
      orientation: frm.doc.orientation,
      build_status: frm.doc.build_status,
      latest_snapshot: frm.doc.latest_snapshot,
      selected_snapshot: frm.doc.selected_snapshot,
      latest_config_order: frm.doc.latest_config_order,
      latest_bom_export_package: frm.doc.latest_bom_export_package
    },
    counts: {
      selections_total: (frm.doc.selections || []).length,
      selections_selected: selected.length,
      execution_log_rows: (frm.doc.execution_log || []).length
    },
    selected_options: selected,
    extra: extra || {}
  };
};

