frappe.ui.form.on('InductOne Build Completion', {
  onload(frm) {
    set_configuration_order_query(frm);
  },

  refresh(frm) {
    set_configuration_order_query(frm);

    if (frm.is_new()) return;

    frm.add_custom_button('Create As-Built Record', async () => {
      try {
        if (!frm.doc.name) {
          throw new Error('Save the Build Completion before creating an As-Built Record.');
        }

        if (!frm.doc.inductone_build) {
          throw new Error('InductOne Build is required.');
        }

        if (!frm.doc.configuration_order) {
          throw new Error('Configuration Order is required.');
        }

        if (!(frm.doc.serials || []).length) {
          throw new Error('At least one serial row is required before creating an As-Built Record.');
        }

        frappe.dom.freeze('Creating As-Built Record...');

        const r = await frappe.call({
          method: 'inductone_tools.inductone_tools.build_completion.create_as_built_from_completion',
          args: {
            completion_name: frm.doc.name
          }
        });

        const asBuiltName = r?.message?.as_built_record;
        if (!asBuiltName) {
          throw new Error('As-Built Record was not returned by the server.');
        }

        await frm.reload_doc();

        frappe.show_alert({
          message: `As-Built Record ${asBuiltName} created.`,
          indicator: 'green'
        });

        frappe.set_route('Form', 'InductOne As-Built Record', asBuiltName);

      } catch (e) {
        console.error(e);
        frappe.msgprint({
          title: 'Create As-Built Record Failed',
          message: `<pre style="white-space:pre-wrap">${frappe.utils.escape_html((e && e.message) ? e.message : String(e))}</pre>`,
          indicator: 'red'
        });
      } finally {
        frappe.dom.unfreeze();
      }
    }, 'InductOne');
  },

  inductone_build(frm) {
    set_configuration_order_query(frm);
  },

  async configuration_order(frm) {
    try {
      if (!frm.doc.configuration_order) return;

      const r = await frappe.call({
        method: 'frappe.client.get',
        args: {
          doctype: 'InductOne Configuration Order',
          name: frm.doc.configuration_order
        }
      });

      const co = r.message;
      if (!co) return;

      const updates = {};

      if (co.inductone_build) {
        updates.inductone_build = co.inductone_build;
      }

      if (co.builder_supplier && 'builder_supplier' in frm.doc) {
        updates.builder_supplier = co.builder_supplier;
      }

      if (co.snapshot && 'configured_snapshot' in frm.doc) {
        updates.configured_snapshot = co.snapshot;
      }

      if (Object.keys(updates).length) {
        await frm.set_value(updates);
      }

    } catch (e) {
      console.error(e);
      frappe.msgprint({
        title: 'Configuration Order Lookup Failed',
        message: `<pre style="white-space:pre-wrap">${frappe.utils.escape_html((e && e.message) ? e.message : String(e))}</pre>`,
        indicator: 'red'
      });
    }
  }
});

function set_configuration_order_query(frm) {
  if (!frm.fields_dict || !frm.fields_dict.configuration_order) return;

  frm.set_query('configuration_order', function() {
    if (!frm.doc.inductone_build) {
      return {};
    }

    return {
      filters: {
        inductone_build: frm.doc.inductone_build
      }
    };
  });
}

frappe.ui.form.on('InductOne As-Built Record', {
  refresh(frm) {
    if (frm.is_new()) return;

    // Don't allow re-locking
    if (frm.doc.status === 'Locked') return;

    frm.add_custom_button('Lock Record', async () => {
      try {
        frappe.dom.freeze('Locking As-Built Record...');

        const updates = {};

        if ('status' in frm.doc) {
          updates.status = 'Locked';
        }

        if ('accepted_at' in frm.doc) {
